"use client";

import { useState } from "react";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import * as z from "zod";
import { motion, AnimatePresence } from "framer-motion";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import {
  PackageIcon,
  ShoppingBasket01Icon,
  Image01Icon,
  Configuration01Icon,
  PlusSignIcon,
  CheckmarkCircle01Icon,
  Loading03Icon,
  Delete02Icon,
  DeliveryTruck01Icon,
  Calendar01Icon,
  StarIcon
} from "hugeicons-react";

import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import {
  Field,
  FieldLabel,
  FieldError,
} from "@/components/ui/field";
import { Separator } from "@/components/ui/separator";
import { cn } from "@/lib/utils";
import { ItemType } from "@/domain/entities/item.entity";
import { ItemRepositoryImpl } from "@/infrastructure/repositories/item.repository.impl";
import { StoreCategoryRepositoryImpl } from "@/infrastructure/repositories/store-category.repository.impl";
import { CreateItemUseCase } from "@/application/use-cases/item/create-item.use-case";
import { GetStoreCategoriesUseCase } from "@/application/use-cases/category/get-store-categories.use-case";
import { CreateCategorySheet } from "./create-category-sheet";
import { ImageCropper } from "@/components/ui/image-cropper";
import { uploadImagesAction, deleteImagesAction } from "@/app/actions/media.actions";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { Badge } from "../ui/badge";

// ÔöÇÔöÇÔöÇ Schema ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

const itemSchema = z.object({
  title: z.string().min(3, "El t├¡tulo debe tener al menos 3 caracteres").max(100),
  description: z.string().min(10, "La descripci├│n debe tener al menos 10 caracteres").max(2000),
  itemType: z.nativeEnum(ItemType),
  price: z.preprocess((val) => (val === "" || val === null || (typeof val === "number" && isNaN(val)) ? undefined : Number(val)), z.number().min(0).optional()) as any,
  categoryId: z.string().uuid("Seleccione una categor├¡a v├ílida").optional().or(z.literal("")),
  trackInventory: z.boolean(),
  stockQuantity: z.preprocess((val) => (val === "" || val === null || (typeof val === "number" && isNaN(val)) ? undefined : Number(val)), z.number().min(0).optional()) as any,
  requiresBooking: z.boolean(),
  isFeatured: z.boolean(),
  discountPrice: z.preprocess((val) => (val === "" || val === null || (typeof val === "number" && isNaN(val)) ? undefined : Number(val)), z.number().min(0).optional()) as any,
});

export type ItemFormValues = {
  title: string;
  description: string;
  itemType: ItemType;
  price?: number;
  categoryId?: string;
  trackInventory: boolean;
  stockQuantity?: number;
  requiresBooking: boolean;
  isFeatured: boolean;
  discountPrice?: number;
};

// ÔöÇÔöÇÔöÇ Components ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

const itemRepository = new ItemRepositoryImpl();
const categoryRepository = new StoreCategoryRepositoryImpl();
const createItemUseCase = new CreateItemUseCase(itemRepository);
const getCategoriesUseCase = new GetStoreCategoriesUseCase(categoryRepository);

interface CreateItemFormProps {
  storeId: string;
  onSuccess: () => void;
  onCancel: () => void;
}

export function CreateItemForm({ storeId, onSuccess, onCancel }: CreateItemFormProps) {
  const queryClient = useQueryClient();
  const [isCategorySheetOpen, setIsCategorySheetOpen] = useState(false);
  const [pendingImages, setPendingImages] = useState<{ file: File; preview: string }[]>([]);
  const [primaryIndex, setPrimaryIndex] = useState(0);
  const [imageError, setImageError] = useState<string | null>(null);

  const {
    register,
    handleSubmit,
    watch,
    setValue,
    formState: { errors },
  } = useForm<ItemFormValues>({
    resolver: zodResolver(itemSchema) as any,
    defaultValues: {
      itemType: ItemType.PRODUCT,
      trackInventory: true,
      requiresBooking: false,
      isFeatured: false,
    },
  });

  const selectedType = watch("itemType");
  const isTrackingInventory = watch("trackInventory");
  const titleValue = watch("title") || "";
  const descriptionValue = watch("description") || "";
  const isFeatured = watch("isFeatured");
  const categoryId = watch("categoryId");

  // TanStack Query for categories
  const { data: categories = [], isLoading: isLoadingCategories } = useQuery({
    queryKey: ["categories", storeId],
    queryFn: async () => {
      const data = await getCategoriesUseCase.execute(storeId);
      return Array.isArray(data) ? data : [];
    },
    enabled: !!storeId,
  });

  // Create Item Mutation
  const createItemMutation = useMutation({
    mutationFn: async (payload: any) => {
      return await createItemUseCase.execute(payload);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["inventory"] });
      onSuccess();
    },
  });

  const handleImageAdd = (file: File) => {
    const preview = URL.createObjectURL(file);
    setPendingImages((prev) => [...prev, { file, preview }]);
    setImageError(null);
  };

  const removeImage = (index: number) => {
    setPendingImages((prev) => {
      const newImages = prev.filter((_, i) => i !== index);
      URL.revokeObjectURL(prev[index].preview);
      return newImages;
    });

    if (primaryIndex === index) {
      setPrimaryIndex(0);
    } else if (primaryIndex > index) {
      setPrimaryIndex(primaryIndex - 1);
    }
  };

  const onSubmit = async (values: ItemFormValues) => {
    if (pendingImages.length === 0) {
      setImageError("Debe subir al menos una imagen.");
      document.getElementById("images-section")?.scrollIntoView({ behavior: "smooth", block: "center" });
      return;
    }

    let uploadedIds: string[] = [];

    try {
      // 1. Bulk Upload Images
      const formData = new FormData();
      pendingImages.forEach((item) => formData.append("files", item.file));
      formData.append("primaryIndex", primaryIndex.toString());

      const uploadResult = await uploadImagesAction(formData);

      if (uploadResult.status !== "success") {
        throw new Error(uploadResult.error || "Error al subir im├ígenes");
      }

      const uploadedData = uploadResult.data as { id: string; url: string; isPrimary: boolean }[];
      uploadedIds = uploadedData.map(img => img.id);

      const imageUrls = uploadedData.map(img => img.url);
      const mainImage = uploadedData.find(img => img.isPrimary)?.url || imageUrls[0];

      // 2. Prepare Final Payload
      const finalPayload = {
        ...values,
        categoryId: values.categoryId === "" ? undefined : values.categoryId,
        trackInventory: values.itemType === ItemType.PRODUCT ? values.trackInventory : false,
        requiresBooking: values.itemType === ItemType.SERVICE ? true : values.requiresBooking,
        storeId,
        mainImage,
        images: imageUrls,
        attributes: {},
      };

      // 3. Execute Mutation
      await createItemMutation.mutateAsync(finalPayload);

    } catch (error) {
      console.error("Submission error:", error);
      if (uploadedIds.length > 0) {
        await deleteImagesAction(uploadedIds);
      }
      alert(error instanceof Error ? error.message : "Error al crear el item");
    }
  };

  const onInvalid = (errors: any) => {
    const firstError = Object.keys(errors)[0];
    const element = document.getElementsByName(firstError)[0];
    if (element) {
      element.scrollIntoView({ behavior: "smooth", block: "center" });
      (element as HTMLElement).focus();
    }
    if (pendingImages.length === 0) setImageError("Debe subir al menos una imagen.");
  };

  const isSubmitting = createItemMutation.isPending;

  return (
    <div className="flex flex-col h-full bg-white dark:bg-gray-950">
      <form
        id="create-item-form"
        onSubmit={handleSubmit(onSubmit, onInvalid)}
        className="flex-1 overflow-y-auto custom-scrollbar p-6 space-y-8 pb-24"
      >

        <section className="space-y-6">
          <div className="flex items-center gap-3 mb-2">
            <div className="h-8 w-8 rounded-lg bg-indigo-100 dark:bg-indigo-900/40 flex items-center justify-center">
              <Configuration01Icon size={18} className="text-indigo-600" />
            </div>
            <h2 className="text-lg font-bold">Informaci├│n General</h2>
          </div>

          <Field>
            <div className="flex items-center justify-between mb-2">
              <FieldLabel>T├¡tulo del {selectedType === ItemType.PRODUCT ? "Producto" : "Servicio"}</FieldLabel>
              <span className={cn(
                "text-[10px] font-bold",
                titleValue.length > 100 ? "text-red-500" : "text-gray-400"
              )}>
                {titleValue.length}/100
              </span>
            </div>
            <Input
              {...register("title")}
              placeholder="Ej. iPhone 15 Pro, Limpieza Dental, Torta de Chocolate..."
              className={cn(
                "rounded-xl border-gray-200 dark:border-gray-800",
                errors.title && "border-red-500 ring-1 ring-red-500/20"
              )}
            />
            <FieldError errors={[errors.title]} />
          </Field>

          <Field>
            <div className="flex items-center justify-between mb-2">
              <FieldLabel>Descripci├│n Detallada</FieldLabel>
              <span className={cn(
                "text-[10px] font-bold",
                descriptionValue.length > 1000 ? "text-red-500" : "text-gray-400"
              )}>
                {descriptionValue.length}/1000
              </span>
            </div>
            <textarea
              {...register("description")}
              className={cn(
                "min-h-[100px] w-full rounded-xl border bg-transparent px-3 py-2 text-sm focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-indigo-500 resize-none",
                errors.description ? "border-red-500 ring-1 ring-red-500/20" : "border-gray-200 dark:border-gray-800"
              )}
              placeholder="Describe las caracter├¡sticas principales..."
            />
            <FieldError errors={[errors.description]} />
          </Field>

          <div className="grid grid-cols-2 gap-4">
            <button
              type="button"
              onClick={() => setValue("itemType", ItemType.PRODUCT)}
              className={cn(
                "flex items-center gap-3 p-4 rounded-2xl border-2 transition-all",
                selectedType === ItemType.PRODUCT
                  ? "border-indigo-600 bg-indigo-50/50 dark:bg-indigo-950/20"
                  : "border-gray-100 dark:border-gray-800 hover:border-indigo-200"
              )}
            >
              <PackageIcon size={24} className={selectedType === ItemType.PRODUCT ? "text-indigo-600" : "text-gray-400"} />
              <div className="text-left">
                <p className="text-sm font-bold">Producto</p>
                <p className="text-[10px] text-gray-400 font-medium">F├¡sico y tangible</p>
              </div>
            </button>
            <button
              type="button"
              onClick={() => setValue("itemType", ItemType.SERVICE)}
              className={cn(
                "flex items-center gap-3 p-4 rounded-2xl border-2 transition-all",
                selectedType === ItemType.SERVICE
                  ? "border-indigo-600 bg-indigo-50/50 dark:bg-indigo-950/20"
                  : "border-gray-100 dark:border-gray-800 hover:border-indigo-200"
              )}
            >
              <Calendar01Icon size={24} className={selectedType === ItemType.SERVICE ? "text-indigo-600" : "text-gray-400"} />
              <div className="text-left">
                <p className="text-sm font-bold">Servicio</p>
                <p className="text-[10px] text-gray-400 font-medium">Agendas y tiempo</p>
              </div>
            </button>
          </div>
        </section>

        <Separator className="bg-gray-100 dark:bg-gray-800" />

        <section className="space-y-6">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3">
              <div className="h-8 w-8 rounded-lg bg-indigo-100 dark:bg-indigo-900/40 flex items-center justify-center">
                <ShoppingBasket01Icon size={18} className="text-indigo-600" />
              </div>
              <h2 className="text-lg font-bold">Categor├¡a</h2>
            </div>
            <Button
              type="button"
              variant="ghost"
              size="sm"
              onClick={() => setIsCategorySheetOpen(true)}
              className="text-indigo-600 hover:text-indigo-700 font-bold gap-1.5"
            >
              <PlusSignIcon size={14} />
              Nueva
            </Button>
          </div>

          <Field>
            <Select
              value={categoryId || ""}
              onValueChange={(val: string | null) => setValue("categoryId", val || "", { shouldValidate: true })}
              disabled={isLoadingCategories}
            >
              <SelectTrigger className="rounded-xl border-gray-200 dark:border-gray-800 h-12 shadow-sm font-medium">
                <SelectValue placeholder={isLoadingCategories ? "Cargando categor├¡as..." : "Selecciona una categor├¡a"} />
              </SelectTrigger>
              <SelectContent className="rounded-xl border-gray-100 dark:border-gray-800 shadow-xl">
                {categories && categories.length > 0 ? (
                  categories.map((cat) => (
                    <SelectItem key={cat.id} value={cat.id} className="font-medium rounded-lg">
                      {cat.name}
                    </SelectItem>
                  ))
                ) : (
                  <div className="p-2 text-xs text-gray-400 text-center">No hay categor├¡as</div>
                )}
              </SelectContent>
            </Select>
            <FieldError errors={[errors.categoryId]} />
          </Field>
        </section>

        <Separator className="bg-gray-100 dark:bg-gray-800" />

        <section className="space-y-6">
          <div className="flex items-center gap-3 mb-2">
            <div className="h-8 w-8 rounded-lg bg-indigo-100 dark:bg-indigo-900/40 flex items-center justify-center">
              <DeliveryTruck01Icon size={18} className="text-indigo-600" />
            </div>
            <h2 className="text-lg font-bold">Precio e Inventario</h2>
          </div>

          <div className="grid grid-cols-2 gap-6">
            <Field>
              <FieldLabel>Precio Base ($)</FieldLabel>
              <Input
                type="number"
                step="0.01"
                {...register("price", { valueAsNumber: true })}
                placeholder="0.00"
                className="rounded-xl border-gray-200 dark:border-gray-800 h-11"
              />
              <FieldError errors={[errors.price]} />
            </Field>

            {selectedType === ItemType.PRODUCT && (
              <Field>
                <FieldLabel>Stock Disponible</FieldLabel>
                <Input
                  type="number"
                  {...register("stockQuantity", { valueAsNumber: true })}
                  placeholder="0"
                  disabled={!isTrackingInventory}
                  className="rounded-xl border-gray-200 dark:border-gray-800 h-11"
                />
              </Field>
            )}
          </div>
        </section>

        <Separator className="bg-gray-100 dark:bg-gray-800" />

        <section className="space-y-6">
          <div className="flex items-center gap-3 mb-2">
            <div className="h-8 w-8 rounded-lg bg-amber-100 dark:bg-amber-900/40 flex items-center justify-center">
              <StarIcon size={18} className="text-amber-600" />
            </div>
            <h2 className="text-lg font-bold">Marketing y Promoci├│n</h2>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <Field>
              <FieldLabel>Precio de Oferta ($)</FieldLabel>
              <Input
                type="number"
                step="0.01"
                {...register("discountPrice", { valueAsNumber: true })}
                placeholder="0.00"
                className="rounded-xl border-gray-200 dark:border-gray-800 h-11"
              />
              <p className="text-[10px] text-gray-400 mt-1 font-bold uppercase tracking-wider">Dejar vac├¡o si no hay oferta</p>
              <FieldError errors={[errors.discountPrice]} />
            </Field>

            <div
              onClick={() => setValue("isFeatured", !isFeatured)}
              className={cn(
                "flex items-center justify-between p-4 rounded-2xl border-2 transition-all cursor-pointer",
                isFeatured
                  ? "border-amber-500 bg-amber-50/50 dark:bg-amber-950/20"
                  : "border-gray-100 dark:border-gray-800 hover:border-amber-200"
              )}
            >
              <div className="flex items-center gap-3">
                <StarIcon size={20} className={isFeatured ? "text-amber-500" : "text-gray-400"} fill={isFeatured ? "currentColor" : "none"} />
                <div>
                  <p className="text-sm font-bold">Destacar Producto</p>
                  <p className="text-[10px] text-gray-400 font-medium">Secciones especiales</p>
                </div>
              </div>
              <div className={cn(
                "h-5 w-5 rounded-full border-2 flex items-center justify-center transition-all",
                isFeatured ? "bg-amber-500 border-amber-500 shadow-lg shadow-amber-500/20" : "border-gray-200"
              )}>
                {isFeatured && <CheckmarkCircle01Icon size={12} className="text-white" />}
              </div>
            </div>
          </div>
        </section>

        <Separator className="bg-gray-100 dark:bg-gray-800" />

        <section id="images-section" className="space-y-6">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3">
              <div className="h-8 w-8 rounded-lg bg-indigo-100 dark:bg-indigo-900/40 flex items-center justify-center">
                <Image01Icon size={18} className="text-indigo-600" />
              </div>
              <h2 className="text-lg font-bold">Im├ígenes del Producto</h2>
            </div>
            <div className="flex items-center gap-3">
              {imageError && <p className="text-[10px] font-black text-red-500 animate-pulse uppercase tracking-widest">{imageError}</p>}
              <Badge variant="outline" className="rounded-full font-black uppercase text-[10px] tracking-widest px-3">
                {pendingImages.length} / 5
              </Badge>
            </div>
          </div>

          <div className="grid grid-cols-3 sm:grid-cols-5 gap-4">
            <AnimatePresence mode="popLayout">
              {pendingImages.map((img, i) => (
                <motion.div
                  key={img.preview}
                  layout
                  initial={{ opacity: 0, scale: 0.8 }}
                  animate={{ opacity: 1, scale: 1 }}
                  exit={{ opacity: 0, scale: 0.8 }}
                  className={cn(
                    "relative aspect-square rounded-2xl border overflow-hidden group shadow-sm transition-all",
                    primaryIndex === i
                      ? "border-indigo-500 ring-4 ring-indigo-500/10"
                      : "border-gray-100 dark:border-gray-800"
                  )}
                >
                  <img
                    src={img.preview}
                    alt="Producto"
                    className="h-full w-full object-cover"
                  />

                  <button
                    type="button"
                    onClick={() => setPrimaryIndex(i)}
                    className={cn(
                      "absolute top-2 left-2 p-1.5 rounded-lg backdrop-blur-md transition-all",
                      primaryIndex === i
                        ? "bg-indigo-600 text-white shadow-lg"
                        : "bg-black/20 text-white/50 hover:bg-black/40 opacity-0 group-hover:opacity-100"
                    )}
                  >
                    <StarIcon size={14} fill={primaryIndex === i ? "currentColor" : "none"} />
                  </button>

                  <button
                    type="button"
                    onClick={() => removeImage(i)}
                    className="absolute top-2 right-2 p-1.5 bg-black/20 hover:bg-red-500 text-white rounded-lg backdrop-blur-md opacity-0 group-hover:opacity-100 transition-all shadow-sm"
                  >
                    <Delete02Icon size={14} />
                  </button>

                  {primaryIndex === i && (
                    <div className="absolute bottom-0 left-0 right-0 bg-indigo-600 py-1">
                      <p className="text-[8px] font-black text-white uppercase text-center tracking-[0.2em]">Portada</p>
                    </div>
                  )}
                </motion.div>
              ))}
            </AnimatePresence>

            {pendingImages.length < 5 && (
              <ImageCropper
                onCropComplete={handleImageAdd}
                outputSize={{ width: 800, height: 800 }}
                label="A├▒adir"
                className="aspect-square border-dashed border-gray-200 dark:border-gray-800 hover:border-indigo-400 hover:bg-indigo-50/10"
                hidePreviewAfterCrop={true}
              />
            )}
          </div>
        </section>

      </form>

      <div className="sticky bottom-0 left-0 right-0 p-6 bg-white/80 dark:bg-gray-950/80 backdrop-blur-md border-t border-gray-100 dark:border-gray-800 flex items-center justify-end gap-3 z-10 -mx-8 -mb-8 mt-8 rounded-b-[2rem]">
        <Button
          type="button"
          variant="ghost"
          onClick={onCancel}
          className="font-bold text-gray-500 h-12 px-6 rounded-2xl"
        >
          Descartar
        </Button>
        <Button
          type="submit"
          form="create-item-form"
          disabled={isSubmitting}
          className="bg-indigo-600 hover:bg-indigo-700 text-white h-12 px-8 rounded-2xl font-black shadow-xl shadow-indigo-600/20 active:scale-95 transition-all w-full sm:w-auto"
        >
          {isSubmitting ? (
            <div className="flex items-center gap-2">
              <Loading03Icon className="animate-spin" size={18} />
              <span>Guardando...</span>
            </div>
          ) : (
            <div className="flex items-center gap-2">
              <CheckmarkCircle01Icon size={18} strokeWidth={2.5} />
              <span>Guardar {selectedType === ItemType.PRODUCT ? "Producto" : "Servicio"}</span>
            </div>
          )}
        </Button>
      </div>

      <CreateCategorySheet
        isOpen={isCategorySheetOpen}
        onClose={() => setIsCategorySheetOpen(false)}
        storeId={storeId}
        onSuccess={(newCat) => {
          queryClient.invalidateQueries({ queryKey: ["categories", storeId] });
          setValue("categoryId", newCat.id);
        }}
      />
    </div>
  );
}
